$('#progressExercise').onchange=renderExerciseProgression; $('#prepareProgression').onclick=e=>{const name=e.currentTarget.dataset.exercise,latest=exerciseEntries().filter(x=>x.name===name).sort((a,b)=>b.workout.date.localeCompare(a.workout.date))[0];if(!latest)return;const recommendation=exerciseRecommendation(latest);sessionExercises=[completeExercise({name:latest.name,load:recommendation.load,sets:recommendation.sets,reps:recommendation.reps,unit:latest.unit,rest:latest.rest,progressionHint:recommendation.progressionHint})];renderExerciseLibrary();$('#workoutType').value='strength';$('#workoutDate').value=localDate();$('#workoutDuration').value=30;$('#workoutNotes').value=`Progression locale · ${latest.name} · ${recommendation.progressionHint}`;$('#workoutDialog').showModal();};
$('#workoutForm').addEventListener('submit', e => { e.preventDefault(); const type = $('#workoutType').value, duration = Number($('#workoutDuration').value), effort = Number($('#workoutEffort').value), distance = Number($('#workoutDistance').value)||0,planId=pendingPlanId; if(!sessionExercises.length&&$('#exerciseName').value.trim())sessionExercises.push(completeExercise({name:$('#exerciseName').value.trim(),load:Number($('#exerciseLoad').value)||0,sets:Number($('#exerciseSets').value)||0,reps:Number($('#exerciseReps').value)||0,unit:$('#exerciseUnit').value,rest:Number($('#exerciseRest').value)||0})); const first=sessionExercises[0]||{}; const xp = Math.min(100, Math.max(15, Math.round(duration / 3 + effort * 5 + sessionExercises.length*3))); state.workouts.unshift({ id: Date.now(), type, duration, effort, distance, date: $('#workoutDate').value, notes: $('#workoutNotes').value.trim(), exercise:first.name||'', load:first.load||0, sets:first.sets||0, reps:first.reps||0, exercises:structuredClone(sessionExercises), xp, planId:planId||undefined }); if(planId){state.plans=state.plans.filter(p=>p.id!==planId);state.agenda=state.agenda.map(a=>a.planId===planId?{...a,completed:true}:a);pendingPlanId=null;} state.xp += xp; state.health += 1; e.target.reset(); sessionExercises=[]; $('#workoutDialog').close(); save(); render(); });
