let lastZonePlan=null;
function zonePlanNoteFor(zone){return zone==='abs'?'💡 Les abdos se voient surtout grâce à l’alimentation : un léger déficit calorique fait fondre le gras qui les cache. Ce programme construit la force et l’endurance du tronc — combine-le avec une assiette propre (protéines, moins de sucres rapides) pour les révéler.':'💡 Le muscle se construit avec la surcharge progressive + assez de protéines + du sommeil. 8 semaines donnent un vrai gain de force ; le volume bien visible vient surtout sur 3–6 mois. La régularité prime.';}
function openZonePlan(zone){const plan=buildZonePlan(zone,8,3);if(!plan)return;lastZonePlan=plan;$('#zonePlanTitle').textContent=`${plan.emoji} Objectif ${plan.label} — ${plan.weeks} semaines`;$('#zonePlanNote').textContent=zonePlanNoteFor(zone);$('#zonePlanExercises').innerHTML='<b>Exercices clés :</b> '+plan.exercises.map(escapeHtml).join(' · ');const rows=plan.blocks.map(b=>`<tr class="${b.deload?'deload':''}"><td>Sem. ${b.week}</td><td>${b.deload?'Décharge · récup':`${plan.perWeek} séances`}</td><td>${b.sets} × ${b.reps}${b.deload?' (léger)':''}</td></tr>`).join('');$('#zonePlanTable').innerHTML='<thead><tr><th>Semaine</th><th>Rythme</th><th>Séries × reps*</th></tr></thead><tbody>'+rows+'</tbody><tfoot><tr><td colspan="3">* répétitions, ou secondes de tenue pour les gainages. 2–3 exercices clés par séance, 45–60 s de repos.</td></tr></tfoot>';$('#zonePlanScheduleStatus').textContent='';$('#zonePlanDialog').showModal();}
function scheduleZonePlan(plan){if(!plan)return 0;const start=new Date();start.setHours(12,0,0,0);const wanted=[1,3,5],totalDays=plan.weeks*7;let added=0;for(let i=1;i<=totalDays;i++){const day=new Date(start);day.setDate(day.getDate()+i);if(!wanted.includes(day.getDay()))continue;const dk=dateKey(day),refId=`zone-${plan.zone}-${dk}`;if(state.agenda.some(a=>a.refId===refId))continue;state.agenda.push(normalizeAgendaItem({id:Date.now()+added,title:`${plan.emoji} ${plan.label} — séance`,date:dk,time:'18:00',kind:'sport',source:'planner',refId,workout:plan.exercises}));added++;}if(added){save();if(typeof refreshAgendaViews==='function')refreshAgendaViews();renderMyDay();renderCommandCenter();renderMonthCalendar();}return added;}
$('#zonePlanBtn')?.addEventListener('click',()=>{const zone=$('#exerciseGoal')?.value;if(zone&&zone!=='all')openZonePlan(zone);});
$('#closeZonePlan')?.addEventListener('click',()=>$('#zonePlanDialog').close());
$('#zonePlanSchedule')?.addEventListener('click',()=>{if(!lastZonePlan)return;const n=scheduleZonePlan(lastZonePlan);$('#zonePlanScheduleStatus').textContent=n?`✓ ${n} séances ajoutées (lun/mer/ven, 18h) sur ${lastZonePlan.weeks} semaines — modifiable dans l’agenda.`:'Déjà programmé : aucun doublon ajouté.';});
let lastWeekProgram=null;
function renderWeekProgram(){const zones=[...document.querySelectorAll('#wpGoals input:checked')].map(i=>i.value);const res=$('#wpResult'),act=$('#wpActions');if(!zones.length){res.innerHTML='<div class="empty-state">Coche au moins un objectif ci-dessus.</div>';act.hidden=true;return;}const prog=buildTrainingWeek(zones,Number($('#wpStrength').value)||3,Number($('#wpRuns').value)||0,$('#wpSameDay')?.checked);lastWeekProgram=prog;if(!prog){act.hidden=true;return;}const rows=prog.days.map(d=>{const tags=`<span class="wp-tag ${d.type}">${escapeHtml(d.title)}</span>`+(d.runs||[]).map(r=>`<span class="wp-tag run">${escapeHtml(r.title)}</span>`).join('');const body=d.exercises&&d.exercises.length?`<ul>${d.exercises.map(e=>`<li>${escapeHtml(e)}</li>`).join('')}</ul>`:d.type==='run'?`<small>${d.long?'Allure très facile, longue durée — endurance fondamentale.':'Allure facile, tu peux parler — récupération active.'}</small>`:'';const runNote=(d.runs||[]).length?`<small class="wp-samerun">${d.runs.some(r=>r.long)?'+ run le même jour (ex. muscu le matin, sortie longue plus tard, à distance).':'+ run facile le même jour (ex. muscu le matin, run l’après-midi).'}</small>`:'';return `<div class="wp-day"><div class="wp-day-h"><b>${d.weekdayLabel}</b>${tags}</div>${body}${runNote}</div>`;}).join('');const rest=7-prog.sessions;res.innerHTML=`<div class="wp-week">${rows}</div><small class="wp-note">${prog.sessions} jour${prog.sessions>1?'s':''} d’entraînement · ${rest} jour${rest>1?'s':''} de repos.${prog.sameDay?' Muscu + run le même jour (espace-les de quelques heures).':' Jours durs espacés, sortie longue le week-end.'} En muscu : 3–4 séries, 45–60 s de repos ; commence léger et progresse.</small>`;act.hidden=false;$('#wpScheduleStatus').textContent='';}
function scheduleWeekProgram(prog,weeks){if(!prog)return 0;weeks=weeks||4;const today=new Date();today.setHours(12,0,0,0);const monday=new Date(today),dow=(monday.getDay()+6)%7;monday.setDate(monday.getDate()-dow+7);let added=0;const add=(title,dk,time,refId,workout)=>{if(state.agenda.some(a=>a.refId===refId))return;state.agenda.push(normalizeAgendaItem({id:Date.now()+added,title,date:dk,time,kind:'sport',source:'planner',refId,workout}));added++;};for(let w=0;w<weeks;w++){prog.days.forEach(d=>{const day=new Date(monday);day.setDate(day.getDate()+w*7+(d.weekday-1));const dk=dateKey(day);if(d.exercises&&d.exercises.length){add(d.title+' — '+d.exercises.slice(0,3).join(', ')+'…',dk,'18:00',`week-muscu-${d.weekday}-${dk}`,d.exercises);}else if(d.type==='run'){add(d.title,dk,'18:00',`week-run-${d.weekday}-${dk}`);}(d.runs||[]).forEach((r,ri)=>add(r.title,dk,'07:30',`week-run${ri}-${d.weekday}-${dk}`));});}if(added){save();if(typeof refreshAgendaViews==='function')refreshAgendaViews();renderMyDay();renderCommandCenter();renderMonthCalendar();}return added;}
$('#wpGenerate')?.addEventListener('click',renderWeekProgram);
$('#wpSchedule')?.addEventListener('click',()=>{if(!lastWeekProgram)return;const n=scheduleWeekProgram(lastWeekProgram,4);$('#wpScheduleStatus').textContent=n?`✓ ${n} séances programmées sur 4 semaines (dès lundi prochain) — modifiables dans l’agenda.`:'Déjà programmé : aucun doublon ajouté.';});
$('#suppHeat').onchange=renderSupplements;$('#suppKind').onchange=renderSupplements;$('#foodSearch').oninput=renderFoods;
$('#foodResults').onclick=e=>{const prot=e.target.closest('[data-log-prot]');if(prot){const food=lastFoodResults[Number(prot.dataset.logProt)];if(food&&food.p>0){bumpProtein(Math.round(Number(food.p)));const old=prot.textContent;prot.textContent='✓ ajouté';setTimeout(()=>{prot.textContent=old;},1000);}return;}const b=e.target.closest('[data-add-food]');if(!b)return;const food=lastFoodResults[Number(b.dataset.addFood)];if(!food)return;if(state.pantry.some(x=>x.n===food.n))return;state.pantry.push({n:food.n,cat:food.cat,kcal:food.kcal,p:food.p,c:food.c,f:food.f});save();renderPantry();renderMealIdeas();b.textContent='✓';setTimeout(()=>{b.textContent='＋';},900);};
