$('#copyShoppingBtn')?.addEventListener('click',()=>{const items=state.pantry.length?buildShoppingList(state.pantry,{style:mealStyle,count:3}):[];if(!items.length)return;const txt='Liste de courses :\n'+items.map(it=>`- ${it.label} (≈ ${it.grams} g) : ${it.suggestions.join(', ')}`).join('\n');navigator.clipboard?.writeText(txt);const b=$('#copyShoppingBtn'),old=b.textContent;b.textContent='Copié ✓';setTimeout(()=>{b.textContent=old;},1200);});
$('#exerciseCards').onclick=e=>{const index=e.target.closest('[data-exercise]')?.dataset.exercise;if(index===undefined)return;selectedExercise=exercises[index];const p=exercisePrescription(selectedExercise),progression=p.unit==='reps'?`Quand toutes les séries sont propres et gardent 2–3 répétitions en réserve, ajoute 1 répétition par série ou un peu de charge.`:`Quand le format reste stable et confortable, ajoute 5 secondes ou quelques pas, jamais tout d’un coup.`;const _pr=personalRecords(state.workouts)[selectedExercise.name],prLine=_pr&&(_pr.load>0||_pr.reps>0)?('<div class="ex-pr"><b>🏆 Record perso :</b> '+(_pr.load>0?_pr.load+' kg':_pr.reps+' reps')+(_pr.date?' · '+_pr.date.split('-').reverse().join('/'):'')+'</div>'):'';$('#exerciseDetailTitle').textContent=selectedExercise.name;$('#exerciseDetailPose').innerHTML=exercisePicture(selectedExercise.name,'',true);$('#exerciseDetailCue').textContent=selectedExercise.cue;$('#exerciseDetailNotes').innerHTML=prLine+`<div><b>Format de départ :</b> ${exerciseFormat(selectedExercise)} · repos ${p.rest}s · environ ${p.minutes} min.</div><div><b>Exécution :</b> ${selectedExercise.explain}</div><div><b>Objectif :</b> ${selectedExercise.goal}</div><div><b>Progression :</b> ${progression}</div><div><b>À éviter :</b> ${selectedExercise.avoid}</div>`;$('#exerciseDetailDialog').showModal();};
$('#closeExerciseDetail').onclick=()=>$('#exerciseDetailDialog').close();$('#addDetailedExercise').onclick=()=>{if(!selectedExercise)return;const p=exercisePrescription(selectedExercise);$('#exerciseName').value=selectedExercise.name;$('#exerciseSets').value=selectedExercise.sets;$('#exerciseReps').value=selectedExercise.reps;$('#exerciseUnit').value=p.unit;$('#exerciseRest').value=p.rest;$('#workoutType').value='strength';$('#exerciseDetailDialog').close();$('#workoutDialog').showModal();};
