$('#closeGuidedWorkout').onclick=()=>{stopGuidedRest();$('#guidedWorkoutDialog').close();};$('#guidedPrevious').onclick=()=>{if(guidedIndex>0){saveGuidedExercise();guidedIndex--;renderGuidedWorkout();}};$('#guidedNext').onclick=()=>{if(!guidedWorkout)return;saveGuidedExercise();if(guidedIndex<guidedWorkout.exercises.length-1){guidedIndex++;renderGuidedWorkout();}else{$('#guidedRecord').focus();}};$('#guidedRestButton').onclick=startGuidedRest;const restTgl=$('#restSoundToggle');if(restTgl){restTgl.checked=restSoundEnabled();restTgl.onchange=()=>{try{localStorage.setItem('irl-rest-sound',restTgl.checked?'on':'off');}catch(_){}if(restTgl.checked)guidedRestCue();};}$('#guidedRecord').onclick=()=>{if(!guidedWorkout)return;saveGuidedExercise();const workout=guidedWorkout;stopGuidedRest();$('#guidedWorkoutDialog').close();prepareSuggestedWorkout(workout);};
