function renderHydration(){const today=localDate(),n=state.nutrition.at(-1),isToday=n&&n.date===today,w=isToday?(Number(n.water)||0):0,trainedToday=state.workouts.some(x=>x.date===today),goal=waterGoalFor(8,trainedToday),st=waterStatus({[today]:w},today,goal);const f=$('#hydraFill');if(f){f.style.width=st.pct+'%';f.classList.toggle('done',st.done);}const l=$('#hydraLabel');if(l)l.textContent=`${st.count} / ${st.goal} verres · ${st.liters} L${st.done?' ✓ objectif atteint':trainedToday?' · +2 (jour de séance)':''}`;const prot=isToday?(Number(n.protein)||0):0,tgt=proteinTarget(state.profile?.weight,state.profile?.goal).gramsPerDay,pp=pct(prot,tgt),pf=$('#proteinFill');if(pf){pf.style.width=pp+'%';pf.classList.toggle('done',tgt>0&&prot>=tgt);}const pl=$('#proteinLabel');if(pl)pl.textContent=`${prot} / ${tgt} g${tgt>0&&prot>=tgt?' ✓ objectif atteint':''}`;}
function bumpWater(delta){const today=localDate();let n=state.nutrition.at(-1);if(!n||n.date!==today){n={date:today,protein:Number($('#proteinInput').value)||0,water:0,fruit:$('#fruitCheck').checked};state.nutrition.push(n);}n.water=Math.max(0,Math.min(40,(Number(n.water)||0)+delta));save();if($('#waterInput'))$('#waterInput').value=n.water;renderHydration();}
$('#waterPlus')?.addEventListener('click',()=>bumpWater(1));
$('#waterMinus')?.addEventListener('click',()=>bumpWater(-1));
function bumpProtein(delta){const today=localDate();let n=state.nutrition.at(-1);if(!n||n.date!==today){n={date:today,protein:0,water:Number($('#waterInput').value)||0,fruit:$('#fruitCheck').checked};state.nutrition.push(n);}n.protein=Math.max(0,Math.min(500,(Number(n.protein)||0)+delta));save();if($('#proteinInput'))$('#proteinInput').value=n.protein;renderHydration();}
