function exportAgendaIcs(){download('level-up-irl-agenda.ics','text/calendar',buildIcs(state.agenda.concat(state.recurring.map(normalizeRecurring))));}
function completeRecurringOn(recId,date){const r=state.recurring.find(x=>x.id===Number(recId));if(!r)return false;r.doneLog=Array.isArray(r.doneLog)?r.doneLog:[];if(r.doneLog.includes(date))return false;r.doneLog.push(date);if(r.kind==='study'){award(15,'focus');}else{save();renderDashboardCore();}return true;}
$('#myDayList').onclick=e=>{const start=e.target.closest('[data-myday-start]');if(start){const plan=state.plans.find(p=>p.id===Number(start.dataset.mydayStart));if(plan)startPlannedWorkout(plan);return;}const rec=e.target.closest('[data-myday-recdone]');if(rec){if(completeRecurringOn(rec.dataset.mydayRecdone,localDate())){renderMyDay();renderCommandCenter();}return;}const doneButton=e.target.closest('[data-myday-done]');if(!doneButton)return;const item=state.agenda.find(a=>a.id===Number(doneButton.dataset.mydayDone));if(!item||item.completed)return;item.completed=true;if(item.kind==='study'){award(15,'focus');}else{save();renderDashboardCore();}renderCommandCenter();};
$('#todoPriorityBtn').onclick=()=>{todoPrioritySelected=!todoPrioritySelected;$('#todoPriorityBtn').classList.toggle('active',todoPrioritySelected);};
$('#todoForm').onsubmit=e=>{e.preventDefault();const text=$('#todoInput').value.trim();if(!text)return;state.todos.push(normalizeTodo({id:Date.now(),text,date:localDate(),priority:todoPrioritySelected?'high':'normal',createdAt:Date.now()}));todoPrioritySelected=false;$('#todoPriorityBtn').classList.remove('active');$('#todoInput').value='';save();renderTodos();renderMyDay();};
$('#habitForm').onsubmit=e=>{e.preventDefault();const name=$('#habitInput').value.trim();if(!name)return;const checked=[...document.querySelectorAll('#habitDays input:checked')].map(i=>Number(i.value));if(!checked.length){$('#habitInput').focus();return;}state.habits.push(normalizeHabit({id:Date.now(),name,xp:10,weekdays:checked.length===7?[]:checked}));save();$('#habitInput').value='';document.querySelectorAll('#habitDays input').forEach(i=>{i.checked=true;});renderHabits();};
$('#habitList').onclick=e=>{const tog=e.target.closest('[data-habit-toggle]'),del=e.target.closest('[data-habit-del]'),today=localDate();if(tog){const h=state.habits.find(x=>x.id===Number(tog.dataset.habitToggle));if(!h)return;h.log=Array.isArray(h.log)?h.log:[];const i=h.log.indexOf(today);if(i>=0){h.log.splice(i,1);state.xp=Math.max(0,state.xp-(h.xp||10));state.life=Math.max(0,state.life-1);save();renderDashboardCore();}else{h.log.push(today);award(h.xp||10,'life');}return;}if(del){state.habits=state.habits.filter(x=>x.id!==Number(del.dataset.habitDel));save();renderHabits();}};
$('#todoList').onclick=e=>{const done=e.target.closest('[data-todo-done]'),undone=e.target.closest('[data-todo-undone]'),move=e.target.closest('[data-todo-today]'),del=e.target.closest('[data-todo-del]');if(done){const t=state.todos.find(x=>x.id===Number(done.dataset.todoDone));if(t&&!t.done){t.done=true;t.doneAt=localDate();award(5,'life');}return;}if(undone){const t=state.todos.find(x=>x.id===Number(undone.dataset.todoUndone));if(t&&t.done){t.done=false;t.doneAt=null;state.xp=Math.max(0,state.xp-5);state.life=Math.max(0,state.life-1);save();renderDashboardCore();}return;}if(move){const t=state.todos.find(x=>x.id===Number(move.dataset.todoToday));if(t){t.date=localDate();save();renderTodos();renderMyDay();}return;}if(del){state.todos=state.todos.filter(x=>x.id!==Number(del.dataset.todoDel));save();renderTodos();renderMyDay();}};
