// Lance une vraie séance guidée (openGuidedWorkout) depuis une liste de noms d'exercices.
function startGuidedFromNames(title,names){const list=(names||[]).map(n=>exercises.find(e=>e.name===n)).filter(Boolean).map(e=>({name:e.name,sets:e.sets,reps:e.reps}));if(!list.length){alert('Aucun exercice reconnu pour cette séance.');return;}openGuidedWorkout({title:title||'Séance guidée',exercises:list});}
$('#dayView').onclick=e=>{const guided=e.target.closest('[data-day-guided]');if(guided){const item=state.agenda.find(a=>a.id===Number(guided.dataset.dayGuided));if(item&&Array.isArray(item.workout)&&item.workout.length){startGuidedFromNames(item.title,item.workout);}return;}const edit=e.target.closest('[data-day-edit]');if(edit){openAgendaEdit(edit.dataset.dayEdit);return;}const postpone=e.target.closest('[data-day-postpone]');if(postpone){const item=state.agenda.find(a=>a.id===Number(postpone.dataset.dayPostpone));if(item){const d=new Date(item.date+'T12:00:00');d.setDate(d.getDate()+1);item.date=dateKey(d);save();renderAgenda();renderMyDay();renderCommandCenter();renderDailyCompass();}return;}const gridBg=e.target.closest('.day-grid');if(gridBg&&!e.target.closest('.dg-event')){const rect=gridBg.getBoundingClientRect(),y=e.clientY-rect.top,gs=Number(gridBg.dataset.gstart)||0,pm=Number(gridBg.dataset.pxm)||0.73;let mins=Math.max(0,Math.min(1439,Math.round((gs+(pm>0?y/pm:0))/15)*15));const p=n=>String(n).padStart(2,'0'),hhmm=p(Math.floor(mins/60))+':'+p(mins%60);if($('#weekQuickDate'))$('#weekQuickDate').value=gridBg.dataset.daykey||dateKey(dayCursor);if($('#weekQuickTime'))$('#weekQuickTime').value=hhmm;const ti=$('#weekQuickTitle');if(ti){ti.focus();ti.scrollIntoView({behavior:'smooth',block:'center'});}return;}const start=e.target.closest('[data-day-start]');if(start){const plan=state.plans.find(p=>p.id===Number(start.dataset.dayStart));if(plan)startPlannedWorkout(plan);return;}const rec=e.target.closest('[data-day-recdone]');if(rec){if(completeRecurringOn(rec.dataset.dayRecdone,dateKey(dayCursor))){renderAgenda();renderMyDay();renderCommandCenter();}return;}const done=e.target.closest('[data-day-done]');if(!done)return;const item=state.agenda.find(a=>a.id===Number(done.dataset.dayDone));if(!item||item.completed)return;item.completed=true;if(item.kind==='study'){award(15,'focus');}else{save();renderDashboardCore();}renderAgenda();renderCommandCenter();};
$('#weekQuickAdd').onsubmit=e=>{e.preventDefault();const allDay=$('#weekQuickAllDay').checked,title=$('#weekQuickTitle').value.trim(),date=$('#weekQuickDate').value;if(!title||!date)return;state.agenda.push(normalizeAgendaItem({id:Date.now(),title,date,time:allDay?'':($('#weekQuickTime').value||''),kind:$('#weekQuickKind').value,priority:$('#weekQuickPriority').value,allDay,location:$('#weekQuickLocation').value.trim(),travelMin:Number($('#weekQuickTravel').value)||0,notes:$('#weekQuickNotes').value.trim()}));save();e.target.reset();$('#weekQuickDate').value=date;if($('#weekQuickTravelStatus'))$('#weekQuickTravelStatus').textContent='';renderAgenda();renderCommandCenter();renderDailyCompass();renderMyDay();};
$('#weekGrid').onclick=e=>{const c=e.target.closest('[data-edit-agenda]');if(c){const item=state.agenda.find(a=>a.id===Number(c.dataset.editAgenda));if(item)openAgendaEdit(item.id);return;}const day=e.target.closest('[data-jump-day]');if(day&&/^\d{4}-\d{2}-\d{2}$/.test(day.dataset.jumpDay)){dayCursor=new Date(day.dataset.jumpDay+'T12:00:00');agendaView='day';try{localStorage.setItem('irl-agenda-view','day');}catch(_){}renderAgenda();}};
