$('#saveVolumeGoal').onclick=()=>{const startKm=Math.max(0,Number($('#volStart').value)||0),targetKm=Math.max(0,Number($('#volTarget').value)||0),date=$('#volDate').value;if(!startKm||!targetKm||!date){$('#volumeVerdict').textContent='Indique ton volume actuel, ta cible et une date.';return;}state.volumeGoal={startKm,targetKm,date};save();renderVolumeGoal();renderTrainingCompanion();};
$('#calendarAgendaDate').value=localDate(); $('#calendarAgendaForm').onsubmit=e=>{e.preventDefault();const repeat=Number($('#calendarRepeat').value),priority=$('#calendarAgendaPriority').value,location=$('#calendarAgendaLocation').value.trim(),notes=$('#calendarAgendaNotes').value.trim(),travelMin=Number($('#calendarAgendaTravel').value)||0,base=new Date(`${$('#calendarAgendaDate').value}T12:00:00`);for(let i=0;i<=repeat;i++){const d=new Date(base);d.setDate(d.getDate()+i*7);state.agenda.push(normalizeAgendaItem({id:Date.now()+i,title:$('#calendarAgendaTitle').value.trim(),date:dateKey(d),time:$('#calendarAgendaTime').value,kind:$('#calendarAgendaKind').value,priority,location,notes,travelMin}));}e.target.reset();$('#calendarAgendaDate').value=localDate();save();renderCommandCenter();renderMonthCalendar();renderDailyCompass();renderMyDay();};
$('#studyStart').value=localDate();
$('#studyPlanForm').onsubmit=e=>{e.preventDefault();const weekdays=[...document.querySelectorAll('#studyDays input:checked')].map(i=>Number(i.value));const events=planStudySessions({title:$('#studyTitle').value.trim()||'Révision',time:$('#studyTime').value||'17:30',durationMin:Number($('#studyDuration').value)||45,weekdays,startDate:$('#studyStart').value||localDate(),examDate:$('#studyExam').value,baseId:Date.now()});if(!events.length){$('#studyPlanStatus').textContent='Choisis au moins un jour, et une date d’examen postérieure au début.';return;}state.agenda=mergePlannedEvents(state.agenda,events).map(normalizeAgendaItem);save();renderCommandCenter();renderMonthCalendar();renderDailyCompass();$('#studyPlanStatus').textContent=`${events.length} créneau${events.length>1?'x':''} de révision jusqu'au ${$('#studyExam').value.split('-').reverse().join('/')} · régénérable sans doublon.`;};
$('#importGlcPlanning').onchange=e=>{const file=e.target.files[0];if(!file)return;if(file.size>1024*1024){$('#glcImportStatus').textContent='Fichier trop volumineux (max 1 Mo).';e.target.value='';return;}const reader=new FileReader();reader.onload=()=>{let events=[];try{events=glcPlanningToEvents(JSON.parse(reader.result),{time:$('#studyTime').value||'17:30',fromDate:localDate(),baseId:Date.now()});}catch{}if(!events.length){$('#glcImportStatus').textContent='Fichier invalide ou aucune échéance à venir. Utilise le bouton « Exporter planning » du Grand Livre.';e.target.value='';return;}state.agenda=mergePlannedEvents(state.agenda,events).map(normalizeAgendaItem);save();renderCommandCenter();renderMonthCalendar();renderDailyCompass();renderMyDay();$('#glcImportStatus').textContent=`✓ ${events.length} jour${events.length>1?'s':''} de révision importé${events.length>1?'s':''} depuis Le Grand Livre · réimport sans doublon.`;e.target.value='';};reader.readAsText(file);};
function applyImportedIcs(text,kind){let events=[];try{events=parseIcs(String(text),{kind,baseId:Date.now()});}catch{}if(!events.length)return{total:0,rec:0};const recEvents=events.filter(ev=>ev.recurrence),oneOff=events.filter(ev=>!ev.recurrence);if(oneOff.length)state.agenda=mergePlannedEvents(state.agenda,oneOff).map(normalizeAgendaItem);recEvents.forEach(ev=>{state.recurring=state.recurring.filter(r=>!(r.refId&&r.refId===ev.refId));state.recurring.push(normalizeRecurring({id:ev.id,title:ev.title,time:ev.allDay?'':ev.time,kind,priority:'normal',rule:ev.recurrence,refId:ev.refId}));});return{total:events.length,rec:recEvents.length};}
function refreshAgendaViews(){save();renderCommandCenter();renderMonthCalendar();renderDailyCompass();renderMyDay();renderRecurring();renderAgenda();}
$('#importIcs').onchange=e=>{const file=e.target.files[0];if(!file)return;if(file.size>3*1024*1024){$('#importIcsStatus').textContent='Fichier trop volumineux (max 3 Mo).';e.target.value='';return;}const reader=new FileReader();reader.onload=()=>{const c=applyImportedIcs(reader.result,$('#importIcsKind').value);if(!c.total){$('#importIcsStatus').textContent='Aucun événement lisible dans ce .ics. Vérifie l’export depuis Google Agenda ou Apple Calendrier.';e.target.value='';return;}refreshAgendaViews();$('#importIcsStatus').textContent=`✓ ${c.total} événement${c.total>1?'s':''} importé${c.total>1?'s':''}${c.rec?` (dont ${c.rec} récurrent${c.rec>1?'s':''} 🔁)`:''} · réimport sans doublon.`;e.target.value='';};reader.readAsText(file);};
let calendarSubs=[];
function renderCalendarSubs(){const box=$('#calSubList');if(!box)return;box.innerHTML=calendarSubs.length?calendarSubs.map(s=>`<div class="birthday-row"><span class="birthday-when">🔄</span><b>${escapeHtml(s.name||'Calendrier')}</b><small>${escapeHtml((s.url||'').replace(/^https:\/\//,'').slice(0,38))}…</small><button class="secondary-button" data-sync-sub="${s.id}">Sync</button><button data-del-sub="${s.id}" aria-label="Supprimer">×</button></div>`).join(''):'<span class="week-insight">Aucun calendrier abonné. Ajoute le lien .ics de ton Google/Apple ci-dessus.</span>';}
async function persistSubs(){if(window.desktop&&window.desktop.saveCalendarSubs){const saved=await window.desktop.saveCalendarSubs(calendarSubs);if(Array.isArray(saved))calendarSubs=saved;}renderCalendarSubs();}
async function syncCalendarSubs(ids,silent){if(!(window.desktop&&window.desktop.fetchCalendar))return;const subs=ids?calendarSubs.filter(s=>ids.includes(s.id)):calendarSubs;if(!subs.length)return;if(!silent&&$('#calSyncStatus'))$('#calSyncStatus').textContent='Synchronisation…';let tot=0,rec=0,err=0;for(const s of subs){try{const r=await window.desktop.fetchCalendar(s.url);if(r&&r.ok){const c=applyImportedIcs(r.text,s.kind||'life');tot+=c.total;rec+=c.rec;}else{err++;if(!silent&&$('#calSyncStatus'))$('#calSyncStatus').textContent=`⚠ ${escapeHtml(s.name||'Calendrier')} : ${escapeHtml((r&&r.error)||'échec')}`;}}catch{err++;}}refreshAgendaViews();if(!silent&&$('#calSyncStatus')&&!err)$('#calSyncStatus').textContent=`✓ ${tot} événement${tot>1?'s':''} synchronisé${tot>1?'s':''}${rec?` (dont ${rec} récurrent${rec>1?'s':''} 🔁)`:''} · ${new Date().toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'})}.`;}
$('#calSubForm')?.addEventListener('submit',async e=>{e.preventDefault();const url=$('#calSubUrl').value.trim();if(!normalizeCalendarUrl(url)){$('#calSyncStatus').textContent='⚠ Lien refusé : il faut une URL https:// (ou webcal://) publique.';return;}const sub={id:Date.now(),name:$('#calSubName').value.trim()||'Calendrier',url,kind:$('#calSubKind').value};calendarSubs.push(sub);await persistSubs();e.target.reset();syncCalendarSubs([sub.id]);});
$('#calSubList')?.addEventListener('click',async e=>{const sync=e.target.closest('[data-sync-sub]'),del=e.target.closest('[data-del-sub]');if(sync){syncCalendarSubs([Number(sync.dataset.syncSub)]);return;}if(del){calendarSubs=calendarSubs.filter(s=>s.id!==Number(del.dataset.delSub));await persistSubs();}});
$('#calSyncAll')?.addEventListener('click',()=>syncCalendarSubs(null,false));
async function setupCalendarSync(){if(!(window.desktop&&window.desktop.getCalendarSubs))return;try{const list=await window.desktop.getCalendarSubs();if(Array.isArray(list))calendarSubs=list;}catch{}renderCalendarSubs();if(calendarSubs.length)syncCalendarSubs(null,true);}
/* Vague S.8 : trajet auto. Point de départ chiffré (safeStorage), calcul opt-in via
   OpenStreetMap (main-only). Le bouton « Estimer » remplit le champ 🚗 du formulaire. */
let travelConfig={home:'',mode:'driving'};
const MODE_LABEL={driving:'🚗 voiture',cycling:'🚲 vélo',walking:'🚶 à pied'};
async function setupTravelStart(){const form=$('#travelStartForm'),est=$('#calendarAgendaEstimate');if(!window.desktop?.getTravelConfig){form?.closest('details')?.setAttribute('hidden','');if(est)est.hidden=true;return;}try{const c=await window.desktop.getTravelConfig();if(c&&typeof c==='object')travelConfig={home:String(c.home||''),mode:['driving','cycling','walking'].includes(c.mode)?c.mode:'driving'};}catch{}if($('#travelHome'))$('#travelHome').value=travelConfig.home;if($('#travelMode'))$('#travelMode').value=travelConfig.mode;form?.addEventListener('submit',async e=>{e.preventDefault();travelConfig={home:$('#travelHome').value.trim(),mode:$('#travelMode').value};try{const saved=await window.desktop.saveTravelConfig(travelConfig);if(saved&&typeof saved==='object')travelConfig=saved;$('#travelStartStatus').textContent='✓ Point de départ enregistré (chiffré sur ton appareil).';}catch{$('#travelStartStatus').textContent='⚠ Enregistrement impossible.';}});}
// Estimation de trajet partagée (formulaire calendrier, ajout rapide, édition).
async function estimateTravelInto(locId,travelId,statusId,btnId){const st=$('#'+statusId);if(!window.desktop?.estimateTravel){if(st)st.textContent='Disponible seulement dans l’app installée.';return;}const to=$('#'+locId).value.trim();if(!travelConfig.home){if(st)st.textContent='⚠ Renseigne d’abord ton « 🧭 Point de départ » (Calendrier → réglages).';return;}if(!to){if(st)st.textContent='⚠ Indique d’abord le 📍 lieu.';$('#'+locId).focus();return;}if(st)st.textContent='Estimation du trajet…';const btn=btnId?$('#'+btnId):null;if(btn)btn.disabled=true;try{const r=await window.desktop.estimateTravel({from:travelConfig.home,to});if(r&&r.ok){const min=r.modes[travelConfig.mode]||r.modes.driving||0;$('#'+travelId).value=min;const dest=String(r.to||'').split(',').slice(0,2).join(',');if(st)st.textContent=`✓ ${min} min (${MODE_LABEL[travelConfig.mode]}) · ${r.modes.distanceKm} km${r.approx?' · à vol d’oiseau':''} → ${dest}`;}else if(st)st.textContent='⚠ '+((r&&r.error)||'échec');}catch{if(st)st.textContent='⚠ Trajet indisponible (réseau).';}finally{if(btn)btn.disabled=false;}}
$('#calendarAgendaEstimate')?.addEventListener('click',()=>estimateTravelInto('calendarAgendaLocation','calendarAgendaTravel','travelEstimateStatus','calendarAgendaEstimate'));
$('#weekQuickEstimate')?.addEventListener('click',()=>estimateTravelInto('weekQuickLocation','weekQuickTravel','weekQuickTravelStatus','weekQuickEstimate'));
$('#editAgendaEstimate')?.addEventListener('click',()=>estimateTravelInto('editAgendaLocation','editAgendaTravel','editAgendaTravelStatus','editAgendaEstimate'));
// Édition d'un événement existant (titre, heure, type, priorité, lieu, trajet, notes).
function openAgendaEdit(id){const it=state.agenda.find(a=>a.id===Number(id));if(!it)return;$('#editAgendaTitle').value=it.title||'';$('#editAgendaDate').value=it.date||localDate();$('#editAgendaTime').value=it.time||'';$('#editAgendaDuration').value=it.durationMin||'';$('#editAgendaKind').value=it.kind||'life';$('#editAgendaPriority').value=it.priority||'normal';$('#editAgendaAllDay').checked=!!it.allDay;$('#editAgendaLocation').value=it.location||'';$('#editAgendaTravel').value=it.travelMin||'';$('#editAgendaNotes').value=it.notes||'';$('#editAgendaTravelStatus').textContent='';$('#agendaEditForm').dataset.id=String(it.id);$('#agendaEditDialog').showModal();}
$('#closeAgendaEdit')?.addEventListener('click',()=>$('#agendaEditDialog').close());
$('#agendaEditForm')?.addEventListener('submit',e=>{e.preventDefault();const id=Number(e.target.dataset.id),i=state.agenda.findIndex(a=>a.id===id);if(i<0){$('#agendaEditDialog').close();return;}const allDay=$('#editAgendaAllDay').checked;state.agenda[i]=normalizeAgendaItem({...state.agenda[i],title:$('#editAgendaTitle').value.trim()||state.agenda[i].title,date:$('#editAgendaDate').value||state.agenda[i].date,time:allDay?'':($('#editAgendaTime').value||''),kind:$('#editAgendaKind').value,priority:$('#editAgendaPriority').value,allDay,location:$('#editAgendaLocation').value.trim(),travelMin:Number($('#editAgendaTravel').value)||0,notes:$('#editAgendaNotes').value.trim(),durationMin:Number($('#editAgendaDuration').value)||state.agenda[i].durationMin||60});save();$('#agendaEditDialog').close();renderAgenda();renderMonthCalendar();renderMyDay();renderCommandCenter();renderDailyCompass();});
$('#duplicateAgendaEdit')?.addEventListener('click',()=>{const id=Number($('#agendaEditForm').dataset.id),it=state.agenda.find(a=>a.id===id);if(!it)return;const copy=duplicateAgendaItem(it,Date.now());if(!copy)return;const fresh=normalizeAgendaItem(copy);state.agenda.push(fresh);save();renderAgenda();renderMonthCalendar();renderMyDay();renderCommandCenter();renderDailyCompass();openAgendaEdit(fresh.id);});
$('#deleteAgendaEdit')?.addEventListener('click',()=>{const id=Number($('#agendaEditForm').dataset.id),it=state.agenda.find(a=>a.id===id);if(!it)return;if(!confirm('Supprimer cet événement ?'))return;state.agenda=state.agenda.filter(a=>a.id!==id);if(it.planId)state.plans=state.plans.filter(p=>p.id!==it.planId);save();$('#agendaEditDialog').close();renderAgenda();renderMonthCalendar();renderMyDay();renderCommandCenter();renderDailyCompass();});
$('#birthdayForm').onsubmit=e=>{e.preventDefault();const name=$('#birthdayName').value.trim(),d=$('#birthdayDate').value,m=/^(\d{4})-(\d{2})-(\d{2})$/.exec(d);if(!name||!m)return;state.birthdays.push(normalizeBirthday({id:Date.now(),name,year:+m[1],month:+m[2],day:+m[3]}));save();e.target.reset();renderBirthdays();renderMonthCalendar();renderMyDay();renderAgenda();};
