const pageGroups={dashboard:['.player-card','.mission-control','.my-day-panel','.habits-panel','.stats-grid','.command-grid','.day-compass-panel','.quest-section'],athlete:['.athlete-header','.athlete-subnav','.athlete-companion','.trail-panel','.training-grid','.planning-panel','.weekly-review-panel','.personal-trends','.charts-panel'],library:['.exercise-library','.weekly-program-panel'],nutrition:['.nutrition-panel','.supplements-panel','.food-search-panel','.kitchen-panel'],focus:['.two-columns','.morning-panel','.reflection-panel','.achievements'],settings:['.settings-page','.reminder-panel']}; function showPage(page){Object.entries(pageGroups).forEach(([name,selectors])=>selectors.forEach(s=>document.querySelectorAll(s).forEach(el=>el.classList.toggle('app-page-hidden',name!==page))));$('.hero').classList.toggle('app-page-hidden',page!=='dashboard');if(page==='athlete'&&typeof showAthleteTab==='function')showAthleteTab(athleteTab);document.querySelectorAll('[data-page]').forEach(b=>b.classList.toggle('active',b.dataset.page===page));let title=document.querySelector('.page-title');if(page==='dashboard'){title?.remove();return;}if(!title){title=document.createElement('div');title.className='page-title';$('.app-nav').after(title);} const pageTitles={athlete:'<p class="eyebrow">ENTRAÎNEMENT & PROGRESSION</p><h2>Mode Athlète</h2><p>Construis, mesure et récupère.</p>',library:'<p class="eyebrow">BIBLIOTHÈQUE</p><h2>Exercices illustrés</h2><p>Recherche un mouvement, vois la technique et prépare ta séance.</p>',nutrition:'<p class="eyebrow">CARBURANT</p><h2>Nutrition</h2><p>Suivi, compléments et repères — sans obsession.</p>',focus:'<p class="eyebrow">ESPRIT & ÉQUILIBRE</p><h2>Focus & Vie</h2><p>Protège ton attention et ton énergie.</p>',settings:'<p class="eyebrow">TON APPLICATION</p><h2>Réglages</h2><p>Apparence, rappels et connexions — au même endroit.</p>'};title.innerHTML=pageTitles[page]||'';}; document.querySelectorAll('[data-page]').forEach(b=>b.onclick=()=>showPage(b.dataset.page));
