$('#exportDataBtn')?.addEventListener('click',async()=>{const st=$('#dataIoStatus');if(!window.desktop?.exportData){if(st)st.textContent='Disponible seulement dans l’app installée.';return;}try{const r=await window.desktop.exportData(JSON.stringify(state));if(st)st.textContent=r&&r.ok?`✓ Sauvegarde exportée : ${r.path}`:(r&&r.canceled?'':'⚠ '+((r&&r.error)||'échec'));}catch{if(st)st.textContent='⚠ Export impossible.';}});
$('#importDataBtn')?.addEventListener('click',async()=>{const st=$('#dataIoStatus');if(!window.desktop?.importData){if(st)st.textContent='Disponible seulement dans l’app installée.';return;}try{const r=await window.desktop.importData();if(!r||!r.ok){if(st&&r&&!r.canceled)st.textContent='⚠ '+((r&&r.error)||'échec');return;}let parsed;try{parsed=JSON.parse(r.text);}catch{if(st)st.textContent='⚠ Fichier illisible (JSON invalide).';return;}if(!confirm('Remplacer toutes tes données actuelles par cette sauvegarde ? (une copie de sécurité automatique existe déjà sur cet appareil.)'))return;state=normalizeState(parsed);save();render();if(st)st.textContent='✓ Données restaurées depuis la sauvegarde.';}catch{if(st)st.textContent='⚠ Import impossible.';}});
let remaining = 25*60, focusDuration=25, interval;function paintTimer(){const m=Math.floor(remaining/60),s=remaining%60;$('#timer').textContent=`${m}:${String(s).padStart(2,'0')}`;}function finishFocusBlock(){const id=Date.now();state.focusSessions.push({id,date:localDate(),minutes:focusDuration,task:state.focusTask||'Bloc de concentration'});state.focusSessions=state.focusSessions.slice(-300);remaining=focusDuration*60;state.timerRuns++;pendingFocusReview=id;award(25,'focus');renderFocusRitual();$('#timerButton').textContent='Session terminée ✓';setTimeout(()=>{$('#timerButton').textContent='Lancer la session';if(!$('#focusReviewDialog').open)$('#focusReviewDialog').showModal();},350);paintTimer();}$('#timerButton').onclick=()=>{if(interval){clearInterval(interval);interval=null;$('#timerButton').textContent='Reprendre';return;}$('#timerButton').textContent='Pause';interval=setInterval(()=>{remaining--;paintTimer();if(remaining<=0){clearInterval(interval);interval=null;finishFocusBlock();}},1000)};$('#timerReset').onclick=()=>{clearInterval(interval);interval=null;remaining=focusDuration*60;paintTimer();$('#timerButton').textContent='Lancer la session';};$('#focusFullscreen').onclick=()=>{const panel=$('.focus-panel');if(document.fullscreenElement)document.exitFullscreen?.();else panel.requestFullscreen?.();};document.addEventListener('fullscreenchange',()=>{$('#focusFullscreen').textContent=document.fullscreenElement?'Quitter plein écran':'Plein écran';});$('#closeFocusReview').onclick=()=>$('#focusReviewDialog').close();$('#saveFocusReview').onclick=()=>{const outcome=$('#focusReviewOutcome').value.trim(),next=$('#focusReviewNext').value.trim();if(!outcome&&!next){$('#focusReviewOutcome').focus();return;}state.focusReviews.push({id:Date.now(),sessionId:pendingFocusReview,date:localDate(),outcome,next});state.focusReviews=state.focusReviews.slice(-300);pendingFocusReview=null;$('#focusReviewOutcome').value='';$('#focusReviewNext').value='';$('#focusReviewDialog').close();save();renderFocusRitual();renderPersonalTrends();};
async function setupDesktopReminders() { if (!window.desktop) return; $('#desktopNote').textContent = 'Les rappels fonctionnent même lorsque la fenêtre est réduite dans la zone de notification.'; const cfg = await window.desktop.getNotifications(); $('#notificationEnabled').checked = cfg.enabled; $('#reminderOne').value = cfg.times[0] || '09:00'; $('#reminderTwo').value = cfg.times[1] || '18:00'; $('#reminderLead').value = cfg.leadMinutes ?? 15; $('#reminderEvening').value = cfg.eveningTime || '21:00'; $('#eveningEnabled').checked = cfg.eveningEnabled !== false; $('#saveReminders').onclick = async () => { await window.desktop.saveNotifications({ enabled: $('#notificationEnabled').checked, times: [$('#reminderOne').value, $('#reminderTwo').value], leadMinutes: Number($('#reminderLead').value) || 15, eveningTime: $('#reminderEvening').value || '21:00', eveningEnabled: $('#eveningEnabled').checked }); $('#desktopNote').textContent = '✓ Rappels enregistrés : résumé du matin, alerte avant chaque bloc, bilan du soir.'; }; $('#testReminder').onclick = () => window.desktop.testNotification(); }
async function offerLocalBackupRestore(){if(savedStateRaw||!window.desktop?.getLocalBackup){automaticBackupReady=true;save();return;}try{const backup=await window.desktop.getLocalBackup();if(backup?.state&&confirm('Une copie locale automatique a été trouvée. Restaurer tes données sur cet appareil ?')){state=normalizeState(backup.state);render();}}catch{}finally{automaticBackupReady=true;save();}}
function setupCollapsibles(){/* C1 : « Ma journée » en tête du dashboard, juste sous le profil */const myDay=document.querySelector('.my-day-panel'),player=document.querySelector('.player-card');if(myDay&&player&&player.nextElementSibling!==myDay)player.after(myDay);/* B3 : regrouper les objectifs — « Objectif ultra-trail » à côté de « Cap sur l'objectif » */const goalPanel=document.querySelector('.goal-panel'),trailPanel=document.querySelector('.trail-panel'),objGrid=goalPanel&&goalPanel.closest('.training-grid');if(objGrid&&trailPanel&&trailPanel.parentElement!==objGrid)objGrid.insertBefore(trailPanel,objGrid.firstElementChild);let collapsed,firstTime=false;try{const raw=localStorage.getItem('irl-collapsed');if(raw===null){firstTime=true;collapsed=new Set(['c:MISSION CONTROL','c:BOUSSOLE LOCALE']);}else collapsed=new Set(JSON.parse(raw||'[]'));}catch(_){collapsed=new Set();}const persist=()=>{try{localStorage.setItem('irl-collapsed',JSON.stringify([...collapsed]));}catch(_){}};if(firstTime)persist();document.querySelectorAll('main.app-shell > section.panel, main.app-shell > section.mission-control, main.app-shell .training-grid > .panel, main.app-shell .command-grid > article.panel').forEach(sec=>{const head=sec.querySelector('.panel-heading, .mission-heading');if(!head||head.querySelector('.collapse-toggle'))return;const eb=sec.querySelector('.eyebrow'),key='c:'+((eb?eb.textContent:sec.className).trim().slice(0,40));const btn=document.createElement('button');btn.type='button';btn.className='collapse-toggle';btn.setAttribute('aria-label','Replier ou déplier cette section');btn.textContent=collapsed.has(key)?'▸':'▾';if(collapsed.has(key))sec.classList.add('collapsed');btn.onclick=e=>{e.stopPropagation();const now=sec.classList.toggle('collapsed');btn.textContent=now?'▸':'▾';btn.setAttribute('aria-expanded',String(!now));if(now)collapsed.add(key);else collapsed.delete(key);persist();};head.appendChild(btn);});}
function setupComfort(){
  const vEl=$('#appVersion');
  if(vEl){if(window.desktop&&window.desktop.getVersion)window.desktop.getVersion().then(v=>{vEl.textContent='IRL LVP UP v'+v;}).catch(()=>{});else vEl.textContent='IRL LVP UP (aperçu web)';}
  const dBtn=$('#densityToggle'),applyDensity=()=>{if(dBtn){const compact=document.documentElement.dataset.density==='compact';dBtn.classList.toggle('active',compact);dBtn.title=compact?'Affichage compact (cliquer pour confort)':'Affichage confort (cliquer pour compact)';}};
  if(dBtn)dBtn.onclick=()=>{const compact=document.documentElement.dataset.density!=='compact';document.documentElement.dataset.density=compact?'compact':'';try{localStorage.setItem('irl-density',compact?'compact':'comfortable');}catch(_){}applyDensity();};
  applyDensity();
  const top=$('#backToTop');
  if(top){const onScroll=()=>{top.hidden=(window.scrollY||document.documentElement.scrollTop||0)<600;};window.addEventListener('scroll',onScroll,{passive:true});onScroll();top.onclick=()=>window.scrollTo({top:0,behavior:'smooth'});}
  // Mise à jour automatique : bannière discrète pilotée par le process principal.
  if(window.desktop&&window.desktop.onUpdateStatus){const banner=$('#updateBanner'),txt=$('#updateBannerText'),inst=$('#updateInstallBtn');window.desktop.onUpdateStatus(s=>{if(!s||!banner)return;if(s.state==='available'){banner.hidden=false;inst.hidden=true;txt.textContent=`Mise à jour v${s.version||''} disponible — téléchargement en cours…`;}else if(s.state==='downloading'){banner.hidden=false;inst.hidden=true;txt.textContent=`Téléchargement de la mise à jour… ${s.percent||0} %`;}else if(s.state==='ready'){banner.hidden=false;inst.hidden=false;txt.textContent=`Mise à jour v${s.version||''} prête à installer.`;}});if(inst)inst.onclick=()=>window.desktop.installUpdate();const dis=$('#updateDismissBtn');if(dis)dis.onclick=()=>{banner.hidden=true;};}
}
